const now = new Date();
const year = now.getFullYear();
const month = now.getMonth(); // 0=Jan
// Previous month
let prevMonth = month - 1;
let prevYear = year;
if (prevMonth < 0) { prevMonth = 11; prevYear = year - 1; }

const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];

return {
  report_month: prevMonth + 1,  // 1-12
  report_year: prevYear,
  month_name: monthNames[prevMonth] + ' ' + prevYear
};

const expenses = $node['Supabase - Fetch Expenses'].all().map(i => i.json);
const revenues = $node['Supabase - Fetch Revenues'].all().map(i => i.json);

const totalExpenses = expenses.reduce((sum, e) => sum + parseFloat(e.amount || 0), 0);
const totalRevenues = revenues.reduce((sum, r) => sum + parseFloat(r.amount || 0), 0);
const netProfit = totalRevenues - totalExpenses;

// Group expenses by category
const byCategory = {};
for (const e of expenses) {
  const cat = e.category || 'other';
  if (!byCategory[cat]) byCategory[cat] = 0;
  byCategory[cat] += parseFloat(e.amount || 0);
}

// Group revenues by source
const bySource = {};
for (const r of revenues) {
  const src = r.source || 'Other';
  if (!bySource[src]) bySource[src] = 0;
  bySource[src] += parseFloat(r.amount || 0);
}

return {
  report_month: $json.report_month,
  report_year: $json.report_year,
  month_name: $json.month_name,
  total_expenses: totalExpenses,
  total_revenues: totalRevenues,
  net_profit: netProfit,
  profit_margin_pct: totalRevenues > 0 ? ((netProfit / totalRevenues) * 100).toFixed(1) : 0,
  expense_categories: byCategory,
  revenue_sources: bySource,
  expense_count: expenses.length,
  revenue_count: revenues.length
};

